import importlib

from langchain_experimental.utilities import PythonREPL

from lfx.custom.custom_component.component import Component
from lfx.io import MultilineInput, Output, StrInput
from lfx.schema.data import Data


class PythonREPLComponent(Component):
    display_name = "Python Interpreter"
    description = "Run Python code with optional imports. Use print() to see the output."
    documentation: str = "https://docs.langflow.org/python-interpreter"
    icon = "square-terminal"

    inputs = [
        StrInput(
            name="global_imports",
            display_name="Global Imports",
            info="A comma-separated list of modules to import globally, e.g. 'math,numpy,pandas'.",
            value="math,pandas",
            required=True,
        ),
        MultilineInput(
            name="python_code",
            display_name="Python Code",
            info="The Python code to execute. Only modules specified in Global Imports can be used.",
            value="print('Hello, World!')",
            input_types=["Message"],
            tool_mode=True,
            required=True,
        ),
    ]

    outputs = [
        Output(
            display_name="Results",
            name="results",
            type_=Data,
            method="run_python_repl",
        ),
    ]

    def get_globals(self, global_imports: str | list[str]) -> dict:
        """Create a globals dictionary with only the specified allowed imports."""
        global_dict = {}

        try:
            if isinstance(global_imports, str):
                modules = [module.strip() for module in global_imports.split(",")]
            elif isinstance(global_imports, list):
                modules = global_imports
            else:
                msg = "global_imports must be either a string or a list"
                raise TypeError(msg)

            for module in modules:
                try:
                    imported_module = importlib.import_module(module)
                    global_dict[imported_module.__name__] = imported_module
                except ImportError as e:
                    msg = f"Could not import module {module}: {e!s}"
                    raise ImportError(msg) from e

        except Exception as e:
            self.log(f"Error in global imports: {e!s}")
            raise
        else:
            self.log(f"Successfully imported modules: {list(global_dict.keys())}")
            return global_dict

    def run_python_repl(self) -> Data:
        try:
            globals_ = self.get_globals(self.global_imports)
            python_repl = PythonREPL(_globals=globals_)
            result = python_repl.run(self.python_code)
            result = result.strip() if result else ""

            self.log("Code execution completed successfully")
            return Data(data={"result": result})

        except ImportError as e:
            error_message = f"Import Error: {e!s}"
            self.log(error_message)
            return Data(data={"error": error_message})

        except SyntaxError as e:
            error_message = f"Syntax Error: {e!s}"
            self.log(error_message)
            return Data(data={"error": error_message})

        except (NameError, TypeError, ValueError) as e:
            error_message = f"Error during execution: {e!s}"
            self.log(error_message)
            return Data(data={"error": error_message})

    def build(self):
        return self.run_python_repl

from __future__ import annotations

import json
import logging
import uuid
from typing import Any, Dict, List, Union

import pymongo
from bson import json_util
from bson.errors import BSONError

from lfx.custom.custom_component.component_with_cache import ComponentWithCache
from lfx.io import DropdownInput, MessageTextInput, MultilineInput, Output
from lfx.schema.message import Message
from lfx.services.cache.utils import CacheMiss

logger = logging.getLogger(__name__)


class MongoDBQueryComponent(ComponentWithCache):
    """MongoDB component that executes queries and returns results."""

    display_name = "MongoDB Query"
    description = "Input to this tool is a detailed and correct MongoDB query, output is a result from the database. If the query is not correct, an error message will be returned. If an error is returned, rewrite the query, check the query, and try again. If you encounter an issue with Unknown column 'xxxx' in 'field list', use mongodb_schema to query the correct collections fields."
    icon = "MongoDB"
    name = "MongoDBQuery"
    metadata = {"keywords": ["mongodb", "database", "query", "execute", "nosql"]}

    inputs = [
        MessageTextInput(
            name="database_uri", 
            display_name="Database URI", 
            required=True,
            info="MongoDB connection string (e.g., mongodb://localhost:27017/)"
        ),
        MessageTextInput(
            name="database_name", 
            display_name="Database Name", 
            required=True,
            info="Name of the MongoDB database"
        ),
        MessageTextInput(
            name="collection_name",
            display_name="Collection Name",
            required=True,
            tool_mode=True,
            info="Name of the MongoDB collection"
        ),
        DropdownInput(
            name="operation",
            display_name="Operation Type",
            options=[
                "find",
                "aggregate", 
                "insert_one",
                "insert_many",
                "update_one",
                "update_many",
                "delete_one",
                "delete_many",
                "count_documents",
                "distinct"
            ],
            value="find",
            required=True,
            tool_mode=True,
            info="Type of MongoDB operation to execute"
        ),
        MultilineInput(
            name="query",
            display_name="Query (JSON)",
            required=True,
            info="MongoDB query in JSON format",
            tool_mode=True
        ),
    ]

    outputs = [
        Output(name="execute_query", display_name="Query Result", method="execute_query"),
    ]

    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.client = None
        self._current_uri = None

    def get_client(self, uri: str):
        """Get or create a MongoDB client connection."""
        if self._shared_component_cache:
            cached_client = self._shared_component_cache.get(uri)
            if not isinstance(cached_client, CacheMiss):
                self.client = cached_client
                self._current_uri = uri
                return self.client

        if self.client is None or self._current_uri != uri:
            if self.client is not None:
                self.client.close()

            try:
                self.client = pymongo.MongoClient(uri, serverSelectionTimeoutMS=5000)
                # Test connection
                self.client.admin.command('ping')
                self._current_uri = uri
                if self._shared_component_cache:
                    self._shared_component_cache.set(uri, self.client)
                logger.info("MongoDB connection established for URI: %s", uri[:30] + "...")
            except Exception as e:
                error_msg = f"Failed to connect to MongoDB: {str(e)}"
                logger.error(error_msg)
                raise ConnectionError(error_msg) from e

        return self.client

    def parse_query(self, query_str: str) -> Dict[str, Any]:
        """Parse and validate JSON query string."""
        try:
            query_dict = json.loads(query_str.strip())
            return {"success": True, "query": query_dict}
        except json.JSONDecodeError as e:
            error_msg = f"Invalid JSON syntax: {str(e)}"
            suggestions = []

            error_details = str(e)
            if "Invalid control character" in error_details:
                suggestions.append("Check for missing quotes around string values")
            if "Expecting property name enclosed in double quotes" in error_details:
                suggestions.append("All object keys must be enclosed in double quotes")
            if "Expecting ',' delimiter" in error_details:
                suggestions.append("Check for missing commas between elements")
            if "Expecting ':' delimiter" in error_details:
                suggestions.append("Check for missing colons after object keys")

            suggestion_text = " | ".join(suggestions) if suggestions else "Check JSON formatting and syntax"
            return {
                "success": False, 
                "error": f"{error_msg}. Suggestions: {suggestion_text}"
            }

    def execute_mongodb_operation(self, collection, operation: str, query_dict: Any) -> Dict[str, Any]:
        """Execute the MongoDB operation and return results."""
        try:
            if operation == "find":
                # Handle projection separately if provided
                if isinstance(query_dict, dict) and "projection" in query_dict:
                    filter_query = {k: v for k, v in query_dict.items() if k != "projection"}
                    projection = query_dict["projection"]
                    cursor = collection.find(filter_query, projection)
                else:
                    cursor = collection.find(query_dict)

                # Convert to list and handle large result sets
                results = []
                count = 0
                max_results = 1000  # Limit to prevent memory issues

                for doc in cursor:
                    if count >= max_results:
                        results.append({"_note": f"Results limited to {max_results} documents. Use limit() in query for more control."})
                        break
                    results.append(doc)
                    count += 1

                # Convert BSON to JSON-serializable format
                json_results = json.loads(json_util.dumps(results))
                return {
                    "success": True, 
                    "results": json_results,
                    "count": count,
                    "operation": operation
                }

            elif operation == "aggregate":
                if not isinstance(query_dict, list):
                    return {"success": False, "error": "Aggregate operation requires an array of pipeline stages"}

                # Execute aggregation pipeline
                cursor = collection.aggregate(query_dict)
                results = []
                count = 0
                max_results = 1000

                for doc in cursor:
                    if count >= max_results:
                        results.append({"_note": f"Results limited to {max_results} documents. Add $limit stage for more control."})
                        break
                    results.append(doc)
                    count += 1

                json_results = json.loads(json_util.dumps(results))
                return {
                    "success": True,
                    "results": json_results,
                    "count": count,
                    "operation": operation
                }

            elif operation == "insert_one":
                if not isinstance(query_dict, dict):
                    return {"success": False, "error": "insert_one requires a JSON object (document)"}

                result = collection.insert_one(query_dict)
                return {
                    "success": True,
                    "results": [{"inserted_id": str(result.inserted_id)}],
                    "operation": operation
                }

            elif operation == "insert_many":
                if not isinstance(query_dict, list):
                    return {"success": False, "error": "insert_many requires an array of documents"}

                result = collection.insert_many(query_dict)
                return {
                    "success": True,
                    "results": [{"inserted_ids": [str(_id) for _id in result.inserted_ids]}],
                    "operation": operation
                }

            elif operation in ["update_one", "update_many"]:
                if not isinstance(query_dict, dict):
                    return {"success": False, "error": f"{operation} requires a JSON object"}
                if "filter" not in query_dict:
                    return {"success": False, "error": f"{operation} requires a 'filter' field"}
                if "update" not in query_dict:
                    return {"success": False, "error": f"{operation} requires an 'update' field"}

                filter_query = query_dict["filter"]
                update_query = query_dict["update"]

                if operation == "update_one":
                    result = collection.update_one(filter_query, update_query)
                else:
                    result = collection.update_many(filter_query, update_query)

                return {
                    "success": True,
                    "results": [{
                        "matched_count": result.matched_count,
                        "modified_count": result.modified_count,
                        "upserted_id": str(result.upserted_id) if result.upserted_id else None
                    }],
                    "operation": operation
                }

            elif operation in ["delete_one", "delete_many"]:
                if not isinstance(query_dict, dict):
                    return {"success": False, "error": f"{operation} requires a JSON object (filter)"}

                if operation == "delete_one":
                    result = collection.delete_one(query_dict)
                else:
                    result = collection.delete_many(query_dict)

                return {
                    "success": True,
                    "results": [{"deleted_count": result.deleted_count}],
                    "operation": operation
                }

            elif operation == "count_documents":
                if not isinstance(query_dict, dict):
                    return {"success": False, "error": "count_documents requires a JSON object (filter)"}

                count = collection.count_documents(query_dict)
                return {
                    "success": True,
                    "results": [{"count": count}],
                    "operation": operation
                }

            elif operation == "distinct":
                if not isinstance(query_dict, dict):
                    return {"success": False, "error": "distinct requires a JSON object"}
                if "field" not in query_dict:
                    return {"success": False, "error": "distinct requires a 'field' parameter"}

                field = query_dict["field"]
                filter_query = query_dict.get("filter", {})

                distinct_values = collection.distinct(field, filter_query)
                # Convert BSON to JSON-serializable format
                json_values = json.loads(json_util.dumps(distinct_values))

                return {
                    "success": True,
                    "results": [{"distinct_values": json_values, "count": len(json_values)}],
                    "operation": operation
                }

            else:
                return {"success": False, "error": f"Unsupported operation: {operation}"}

        except pymongo.errors.OperationFailure as e:
            error_msg = str(e)
            # Check for common field-related errors
            if "unknown" in error_msg.lower() and ("field" in error_msg.lower() or "column" in error_msg.lower()):
                return {
                    "success": False,
                    "error": f"Field error: {error_msg}",
                    "suggestion": "Use mongodb_schema tool to check the correct field names in this collection"
                }
            return {"success": False, "error": f"MongoDB operation failed: {error_msg}"}

        except BSONError as e:
            return {"success": False, "error": f"BSON error: {str(e)}"}

        except Exception as e:
            return {"success": False, "error": f"Unexpected error during {operation}: {str(e)}"}

    def execute_query(self) -> Message:
        """Execute the MongoDB query and return results."""
        exec_id = str(uuid.uuid4())[:8]
        logger.info("Execution ID: %s", exec_id)

        try:
            # Get current parameters
            uri = self.database_uri
            database_name = self.database_name
            collection_name = self.collection_name
            operation = self.operation.lower()
            query_str = self.query

            # Handle different input types for query (string or other)
            if not isinstance(query_str, str):
                query_str = str(query_str) if query_str else ""

            logger.info(
                "MongoDB query execution [%s]: Database=%s, Collection=%s, Operation=%s, URI=%s", 
                exec_id, 
                database_name,
                collection_name,
                operation,
                uri[:30] + "..."
            )

            # Validate inputs
            if not uri or not uri.strip():
                error_msg = "❌ Error: Database URI cannot be empty."
                logger.error("Error [%s]: %s", exec_id, error_msg)
                return Message(text=error_msg)

            if not database_name or not database_name.strip():
                error_msg = "❌ Error: Database name cannot be empty."
                logger.error("Error [%s]: %s", exec_id, error_msg)
                return Message(text=error_msg)

            if not collection_name or not collection_name.strip():
                error_msg = "❌ Error: Collection name cannot be empty."
                logger.error("Error [%s]: %s", exec_id, error_msg)
                return Message(text=error_msg)

            if not query_str or not query_str.strip():
                error_msg = "❌ Error: Query cannot be empty. Please provide a valid JSON query."
                logger.error("Error [%s]: %s", exec_id, error_msg)
                return Message(text=error_msg)

            # Parse query
            parse_result = self.parse_query(query_str)
            if not parse_result["success"]:
                error_msg = f"❌ JSON Parse Error: {parse_result['error']}"
                logger.error("Parse Error [%s]: %s", exec_id, error_msg)
                return Message(text=error_msg)

            query_dict = parse_result["query"]

            # Connect to database
            try:
                client = self.get_client(uri.strip())
                database = client[database_name.strip()]
                collection = database[collection_name.strip()]

                # Check if collection exists (for read operations)
                if operation in ["find", "aggregate", "count_documents", "distinct"]:
                    collections = database.list_collection_names()
                    if collection_name not in collections:
                        warning_msg = f"⚠️  Warning: Collection '{collection_name}' does not exist in database '{database_name}'"
                        logger.warning("Collection Warning [%s]: %s", exec_id, warning_msg)
                        return Message(text=f"{warning_msg}\n\nAvailable collections: {', '.join(collections[:10])}")

            except ConnectionError as e:
                error_msg = f"❌ Connection Error: {str(e)}"
                logger.error("Connection Error [%s]: %s", exec_id, error_msg)
                return Message(text=error_msg)
            except Exception as e:
                error_msg = f"❌ Database Error: {str(e)}"
                logger.error("Database Error [%s]: %s", exec_id, error_msg)
                return Message(text=error_msg)

            # Execute operation
            execution_result = self.execute_mongodb_operation(collection, operation, query_dict)

            if not execution_result["success"]:
                error_msg = f"❌ Query Execution Error: {execution_result['error']}"
                if "suggestion" in execution_result:
                    error_msg += f"\n💡 Suggestion: {execution_result['suggestion']}"
                logger.error("Execution Error [%s]: %s", exec_id, error_msg)
                return Message(text=error_msg)

            # Format successful results
            results = execution_result["results"]
            operation_type = execution_result["operation"]

            output_lines = []
            output_lines.append(f"✅ Query executed successfully")
            output_lines.append(f"📋 Operation: {operation_type}")
            output_lines.append(f"🗄️  Database: {database_name}")
            output_lines.append(f"📄 Collection: {collection_name}")

            if "count" in execution_result:
                output_lines.append(f"📊 Results: {execution_result['count']} documents")

            output_lines.append(f"\n🔍 Query:")
            output_lines.append(f"{json.dumps(query_dict, indent=2, default=str)}")

            output_lines.append(f"\n📤 Results:")
            if results:
                if len(results) == 1 and isinstance(results[0], dict) and len(results[0]) <= 3:
                    # Simple single result (like counts, insert results)
                    output_lines.append(f"{json.dumps(results[0], indent=2, default=str)}")
                else:
                    # Multiple or complex results
                    for i, result in enumerate(results[:10], 1):  # Show first 10 results
                        if isinstance(result, dict) and "_note" in result:
                            output_lines.append(f"📝 {result['_note']}")
                        else:
                            output_lines.append(f"Document {i}:")
                            output_lines.append(f"{json.dumps(result, indent=2, default=str)}")
                            if i < len(results):
                                output_lines.append("")  # Add spacing between documents

                    if len(results) > 10:
                        output_lines.append(f"... and {len(results) - 10} more documents")
            else:
                output_lines.append("No results returned")

            result_text = "\n".join(output_lines)
            logger.info("Query execution completed [%s]: SUCCESS", exec_id)

            return Message(text=result_text)

        except Exception as e:
            error_msg = f"❌ Unexpected Error: {str(e)}"
            logger.error("Unexpected Error [%s]: %s", exec_id, error_msg)
            return Message(text=error_msg)

    def __del__(self):
        """Clean up MongoDB connection when component is destroyed."""
        if hasattr(self, "client") and self.client is not None:
            self.client.close()
            logger.info("MongoDB connection closed.")

from lfx.base.composio.composio_base import ComposioBaseComponent


class ComposioGmailAPIComponent(ComposioBaseComponent):
